class InstallerAPI:
    def __init__(self):
        self.window = None
        self.is_mac = platform.system() == "Darwin"
        self._install_log = []
        self._warnings = []
        self._errors = []

    def set_window(self, window):
        self.window = window

    def check_prerequisites(self):
        results = {}
        if self.is_mac:
            results["zotero"] = os.path.isdir("/Applications/Zotero.app")
            results["claude"] = os.path.isdir(
                os.path.expanduser("~/Library/Application Support/Claude"))
        else:
            results["zotero"] = any(
                os.path.isfile(os.path.join(p, "Zotero", "zotero.exe"))
                for p in [os.environ.get("ProgramFiles", ""),
                          os.environ.get("ProgramFiles(x86)", ""),
                          os.environ.get("LOCALAPPDATA", "")]
                if p)
            results["claude"] = os.path.isdir(
                os.path.join(os.environ.get("APPDATA", ""), "Claude"))
        results["git"] = shutil.which("git") is not None
        results["uv"] = (shutil.which("uv") is not None
                         or os.path.isfile(os.path.expanduser("~/.local/bin/uv"))
                         or os.path.isfile(os.path.expanduser("~/.cargo/bin/uv")))
        results["existing_credentials"] = self._get_existing_credentials()
        return results

    def _get_existing_credentials(self):
        if self.is_mac:
            cfg = os.path.expanduser(
                "~/Library/Application Support/Claude/claude_desktop_config.json")
        else:
            cfg = os.path.join(os.environ.get("APPDATA", ""), "Claude",
                               "claude_desktop_config.json")
        try:
            with open(cfg) as f:
                c = json.load(f)
            env = c.get("mcpServers", {}).get("zotero", {}).get("env", {})
            key = env.get("ZOTERO_API_KEY", "")
            lid = env.get("ZOTERO_LIBRARY_ID", "")
            if key and lid:
                masked = key[:4] + "***" + key[-4:] if len(key) >= 8 else "***"
                return {"masked_key": masked, "library_id": lid, "raw_key": key}
        except Exception:
            pass
        return None

    def open_url(self, url):
        """Open a URL in the default browser."""
        import webbrowser
        webbrowser.open(url)

    def install(self, config):
        self._install_log = []
        self._warnings = []
        self._errors = []
        thread = threading.Thread(target=self._run_install, args=(config,), daemon=True)
        thread.start()

    def _js(self, code):
        if self.window:
            self.window.evaluate_js(code)

    def _log(self, msg, level="info"):
        self._js(f'addLog({json.dumps(msg)}, {json.dumps(level)})')

    def _set_progress(self, step, total=5):
        self._js(f'setProgress({step}, {total})')

    def _log_raw(self, step, command, stdout, stderr, returncode, duration):
        """Buffer raw subprocess output for the diagnostic report."""
        self._install_log.append({
            "step": step,
            "command": command,
            "stdout": stdout or "",
            "stderr": stderr or "",
            "returncode": returncode,
            "duration_seconds": duration,
            "timestamp": time.strftime("%Y-%m-%d %H:%M:%S"),
        })

    def _complete(self, success=True, msg="", warnings=None):
        w = warnings if warnings is not None else self._warnings
        self._js(f'showComplete({json.dumps(success)}, {json.dumps(msg)}, {json.dumps(w)})')

    def _run_install(self, config):
        try:
            api_key = config.get("api_key", "")
            library_id = config.get("library_id", "")
            pdf_index = config.get("pdf_index_pages", 50)
            pdf_display = config.get("pdf_display_pages", 10)
            build_db = config.get("build_db", True)
            use_secret = config.get("use_secret", False)

            # Step 1: uv
            self._set_progress(1)
            self._log("Checking for uv package manager...")
            if shutil.which("uv"):
                self._log("uv is already installed", "success")
            else:
                self._log("Installing uv...")
                cmd = ("curl -LsSf https://astral.sh/uv/install.sh | sh" if self.is_mac
                       else "irm https://astral.sh/uv/install.ps1 | iex")
                shell = ["bash", "-c", cmd] if self.is_mac else ["powershell", "-Command", cmd]
                t0 = time.time()
                proc = subprocess.run(shell, capture_output=True, text=True, timeout=120)
                self._log_raw("Step 1: Install uv", cmd, proc.stdout, proc.stderr,
                              proc.returncode, time.time() - t0)
                if proc.returncode == 0:
                    os.environ["PATH"] = (os.path.expanduser("~/.local/bin")
                                          + os.pathsep + os.environ.get("PATH", ""))
                    self._log("uv installed", "success")
                else:
                    self._log("Failed to install uv", "error")
                    self._complete(False, "Could not install uv.")
                    return

            # Step 2: Server
            self._set_progress(2)
            if use_secret:
                self._log("Installing from Eugene's branch (development version)...")
            else:
                self._log("Installing Zotero MCP server...")
            self._log("This may take a minute or two...")
            uv = shutil.which("uv") or os.path.expanduser("~/.local/bin/uv")
            if use_secret:
                pkg = "zotero-mcp-server[all] @ git+https://github.com/ehawkin/zotero-mcp@secret"
            else:
                pkg = "zotero-mcp-server[all]"
            t0 = time.time()
            proc = subprocess.run([uv, "tool", "install", "--force", "--reinstall", pkg],
                                  capture_output=True, text=True, timeout=300)
            self._log_raw("Step 2: Install server", f"{uv} tool install --force --reinstall {pkg}",
                          proc.stdout, proc.stderr, proc.returncode, time.time() - t0)
            if proc.returncode == 0:
                if use_secret:
                    self._log("Server installed (from Eugene's branch)", "success")
                else:
                    self._log("Server installed", "success")
            else:
                self._log(f"Install error: {proc.stderr[:200]}", "error")
                self._complete(False, "Server installation failed.")
                return

            mcp_path = shutil.which("zotero-mcp") or os.path.expanduser("~/.local/bin/zotero-mcp")
            if not os.path.isfile(mcp_path):
                self._complete(False, "Could not find zotero-mcp after installation.")
                return

            # Step 3: Claude config
            self._set_progress(3)
            self._log("Configuring Claude Desktop...")
            if self.is_mac:
                cfg_dir = os.path.expanduser("~/Library/Application Support/Claude")
            else:
                cfg_dir = os.path.join(os.environ.get("APPDATA", ""), "Claude")
            cfg_file = os.path.join(cfg_dir, "claude_desktop_config.json")
            os.makedirs(cfg_dir, exist_ok=True)

            if os.path.isfile(cfg_file):
                ts = time.strftime("%Y-%m-%d_%H%M")
                backup_path = cfg_file.replace(".json", f"_backup_{ts}.json")
                shutil.copy2(cfg_file, backup_path)
                self._log("Config backed up", "success")

            existing = {}
            config_was_corrupted = False
            if os.path.isfile(cfg_file):
                try:
                    with open(cfg_file) as f:
                        existing = json.load(f)
                except Exception:
                    config_was_corrupted = True
                    self._warnings.append(
                        f"Your existing Claude config had a syntax error. "
                        f"Backup saved to {backup_path}. "
                        f"Other MCP servers may need to be re-added from the backup.")
                    self._log("Existing config had errors — backup saved", "warning")

            env_vars = {"ZOTERO_LOCAL": "true"}
            if api_key and library_id:
                env_vars.update({"ZOTERO_API_KEY": api_key,
                                 "ZOTERO_LIBRARY_ID": library_id,
                                 "ZOTERO_LIBRARY_TYPE": "user"})

            existing.setdefault("mcpServers", {})
            existing["mcpServers"]["zotero"] = {"command": mcp_path, "env": env_vars}
            with open(cfg_file, "w") as f:
                json.dump(existing, f, indent=2)
                f.write("\n")

            # Read-back verification
            try:
                with open(cfg_file) as f:
                    readback = json.load(f)
                zotero_cmd = readback.get("mcpServers", {}).get("zotero", {}).get("command", "")
                if not zotero_cmd or not os.path.isfile(zotero_cmd):
                    self._warnings.append(
                        f"Config written but the MCP binary path '{zotero_cmd}' "
                        f"could not be verified.")
                    self._log("Config written — binary path could not be verified", "warning")
                else:
                    mode = "hybrid (read + write)" if api_key else "local-only (read)"
                    self._log(f"Configured: {mode} mode", "success")
            except Exception:
                self._warnings.append("Config was written but could not be verified.")
                self._log("Config written but could not be verified", "warning")

            self._log_raw("Step 3: Configure Claude", f"Write {cfg_file}",
                          json.dumps(existing, indent=2), "", 0, 0)

            # Check if Claude Desktop is running
            if self.is_mac:
                try:
                    proc = subprocess.run(["pgrep", "-x", "Claude"],
                                          capture_output=True, text=True, timeout=5)
                    if proc.returncode == 0:
                        self._log("Claude Desktop is running — restart it for changes to take effect", "warning")
                except Exception:
                    pass

            # Step 4: Semantic search
            self._set_progress(4)
            self._log("Setting up semantic search...")
            sem_dir = os.path.expanduser("~/.config/zotero-mcp")
            sem_file = os.path.join(sem_dir, "config.json")
            os.makedirs(sem_dir, exist_ok=True)

            sem = {}
            if os.path.isfile(sem_file):
                try:
                    with open(sem_file) as f:
                        sem = json.load(f)
                except Exception:
                    self._log("Existing search config had errors — starting fresh", "warning")

            ss = sem.setdefault("semantic_search", {})
            ss.setdefault("update_config", {}).update(
                {"auto_update": True, "update_frequency": "startup"})
            ss.setdefault("extraction", {}).update(
                {"pdf_max_pages": pdf_index, "fulltext_display_max_pages": pdf_display})

            with open(sem_file, "w") as f:
                json.dump(sem, f, indent=2)
                f.write("\n")

            # Read-back verification
            try:
                with open(sem_file) as f:
                    json.load(f)
                self._log(f"Search: index {pdf_index} pages, display {pdf_display} pages", "success")
            except Exception:
                self._warnings.append("Semantic search config was written but could not be verified.")
                self._log("Search config written but could not be verified", "warning")

            self._log_raw("Step 4: Semantic search config", f"Write {sem_file}",
                          json.dumps(sem, indent=2), "", 0, 0)

            # Step 5: Database
            if build_db:
                self._set_progress(5)

                # Pre-check: is Zotero running and is the local API enabled?
                zotero_status = "not_running"  # not_running, api_disabled, ready
                try:
                    import urllib.request, urllib.error
                    req = urllib.request.Request("http://localhost:23119/api/users/0/items?limit=1")
                    urllib.request.urlopen(req, timeout=3)
                    zotero_status = "ready"
                except urllib.error.HTTPError:
                    zotero_status = "api_disabled"
                except Exception:
                    zotero_status = "not_running"

                if zotero_status == "not_running":
                    self._warnings.append(
                        "Zotero needs to be running to build the search database. "
                        "It will build automatically next time you open Claude Desktop.")
                    self._log("Zotero not running — database will auto-build later", "warning")
                elif zotero_status == "api_disabled":
                    self._warnings.append(
                        "Zotero is running, but the local API is not enabled. "
                        "In Zotero, go to Settings \u2192 Advanced and check "
                        "\u201cAllow other applications on this computer to communicate with Zotero\u201d, "
                        "then restart Claude Desktop to build the search database.")
                    self._log("Zotero local API not enabled — enable it in Settings \u2192 Advanced", "warning")
                else:
                    self._log("Building search database (may take several minutes)...")
                    env = os.environ.copy()
                    env["ZOTERO_LOCAL"] = "true"
                    t0 = time.time()
                    proc = subprocess.run([mcp_path, "update-db", "--fulltext"],
                                          env=env, capture_output=True, text=True, timeout=1800)
                    self._log_raw("Step 5: Build database",
                                  f"{mcp_path} update-db --fulltext",
                                  proc.stdout, proc.stderr, proc.returncode,
                                  time.time() - t0)
                    if proc.returncode == 0:
                        self._log("Database built", "success")
                    else:
                        self._warnings.append(
                            "Database build had issues — will auto-build on next startup.")
                        self._log("Database build had issues — will auto-build later", "warning")
            else:
                self._set_progress(5)
                self._log("Skipping database (will auto-build on first use)", "info")

            self._complete(True)

        except subprocess.TimeoutExpired:
            self._complete(False, "Operation timed out. Please try again.")
        except Exception as e:
            self._complete(False, str(e))

    def get_install_log(self):
        """Return the raw install log for the diagnostic report."""
        return self._install_log

    def get_warnings(self):
        """Return warnings collected during installation."""
        return self._warnings

    def _find_python(self):
        """Find a real Python 3 interpreter (sys.executable is the app itself in PyInstaller)."""
        if not hasattr(sys, '_MEIPASS'):
            return sys.executable
        # In a PyInstaller bundle, find system Python
        for name in ["python3", "python"]:
            path = shutil.which(name)
            if path:
                return path
        # Check common locations
        for path in ["/usr/bin/python3", "/usr/local/bin/python3",
                     "/opt/homebrew/bin/python3"]:
            if os.path.isfile(path):
                return path
        return None

    def _find_diagnostic_script(self):
        """Locate the standalone diagnostic script."""
        # When bundled with PyInstaller, check _MEIPASS first
        if hasattr(sys, '_MEIPASS'):
            bundled = os.path.join(sys._MEIPASS, 'zotero-mcp-diagnostic.py')
            if os.path.isfile(bundled):
                return bundled
        # Check relative to this file's directory (dev mode)
        here = os.path.dirname(os.path.abspath(__file__))
        candidate = os.path.join(os.path.dirname(here), 'zotero-mcp-diagnostic.py')
        if os.path.isfile(candidate):
            return candidate
        return None

    def run_diagnostics(self):
        """Run the diagnostic script with --stream, pushing each check to the GUI in real time."""
        script = self._find_diagnostic_script()
        if not script:
            return {"error": "Diagnostic tool not found."}
        python = self._find_python()
        if not python:
            return {"error": "Python interpreter not found."}

        def _stream():
            try:
                proc = subprocess.Popen(
                    [python, "-u", script, "--stream"],
                    stdout=subprocess.PIPE, stderr=subprocess.PIPE,
                    text=True, bufsize=1,
                    env={**os.environ, "PYTHONDONTWRITEBYTECODE": "1",
                         "PYTHONUNBUFFERED": "1"})
            except FileNotFoundError:
                self._js("diagError('Python interpreter not found.')")
                return
            except Exception as e:
                self._js(f"diagError({json.dumps(str(e))})")
                return

            checks = []
            report_lines = []
            in_report = False

            try:
                for line in proc.stdout:
                    line = line.rstrip("\n")
                    if line.startswith("HEADER:"):
                        label = line[7:]
                        self._js(f"diagHeader({json.dumps(label)})")
                    elif line.startswith("PROGRESS:"):
                        msg = line[9:]
                        self._js(f"diagProgress({json.dumps(msg)})")
                    elif line.startswith("CHECK:"):
                        parts = line.split(":", 3)
                        if len(parts) >= 4:
                            name, status, detail = parts[1], parts[2], parts[3]
                            checks.append({"name": name, "status": status, "detail": detail})
                            self._js(f"diagCheck({json.dumps(name)},{json.dumps(status)},{json.dumps(detail)})")
                    elif line == "REPORT:BEGIN":
                        in_report = True
                    elif line == "REPORT:END":
                        in_report = False
                    elif in_report:
                        report_lines.append(line)

                proc.wait(timeout=10)
            except Exception:
                proc.kill()

            report = "\n".join(report_lines)
            self._diag_checks = checks
            self._diag_report = report
            self._js(f"diagDone({json.dumps(report)})")

        threading.Thread(target=_stream, daemon=True).start()
        return {"streaming": True}

    def get_diag_results(self):
        """Return cached diagnostic results (for post-install report generation)."""
        return {
            "checks": getattr(self, "_diag_checks", []),
            "report": getattr(self, "_diag_report", "")
        }

    def _run_diagnostics_sync(self):
        """Run the diagnostic script synchronously and return parsed results."""
        script = self._find_diagnostic_script()
        if not script:
            return {"error": "Diagnostic tool not found."}
        python = self._find_python()
        if not python:
            return {"error": "Python interpreter not found."}
        try:
            proc = subprocess.run(
                [python, script, "--stream"],
                capture_output=True, text=True, timeout=30,
                env={**os.environ, "PYTHONDONTWRITEBYTECODE": "1"})
        except subprocess.TimeoutExpired:
            return {"error": "Diagnostic check timed out after 30 seconds."}
        except Exception as e:
            return {"error": str(e)}

        checks = []
        report_lines = []
        in_report = False
        for line in proc.stdout.splitlines():
            if line.startswith("CHECK:"):
                parts = line.split(":", 3)
                if len(parts) >= 4:
                    checks.append({"name": parts[1], "status": parts[2], "detail": parts[3]})
            elif line == "REPORT:BEGIN":
                in_report = True
            elif line == "REPORT:END":
                in_report = False
            elif in_report:
                report_lines.append(line)
        return {"checks": checks, "report": "\n".join(report_lines)}

    def generate_post_install_report(self):
        """Run diagnostics synchronously and append the install log to the report."""
        result = self._run_diagnostics_sync()
        if "error" in result:
            return result

        report = result.get("report", "")

        # Append install log if we have one
        if self._install_log:
            report += "\n" + "=" * 50 + "\n"
            report += "INSTALL LOG\n"
            report += "=" * 50 + "\n"
            for entry in self._install_log:
                report += f"\n  STEP: {entry.get('step', 'unknown')}\n"
                report += f"  Time: {entry.get('timestamp', 'unknown')} ({entry.get('duration_seconds', 0):.1f}s)\n"
                report += f"  Command: {entry.get('command', 'unknown')}\n"
                report += f"  Return code: {entry.get('returncode', 'unknown')}\n"
                report += f"  STDOUT: {entry.get('stdout', '(empty)')[:500]}\n"
                report += f"  STDERR: {entry.get('stderr', '(empty)')[:500]}\n"

        # Append install warnings if any
        if self._warnings:
            report += "\n" + "=" * 50 + "\n"
            report += "INSTALL WARNINGS\n"
            report += "=" * 50 + "\n"
            for w in self._warnings:
                report += f"  - {w}\n"

        result["report"] = report
        return result

    def save_diagnostic_report(self, report_text, report_type=None):
        """Save the diagnostic report using a native Save dialog."""
        import webview
        try:
            ts = time.strftime("%Y-%m-%d_%H%M")
            if report_type == "install":
                default_name = f"Zotero MCP Setup Report {ts}.txt"
            else:
                default_name = f"Zotero MCP Diagnostic {ts}.txt"
            result = self.window.create_file_dialog(
                webview.SAVE_DIALOG,
                directory=os.path.expanduser("~/Desktop"),
                save_filename=default_name,
                file_types=("Text files (*.txt)",))
            if not result:
                return {"cancelled": True}
            filepath = result if isinstance(result, str) else result[0]
            with open(filepath, "w") as f:
                f.write(report_text)
            return {"path": filepath}
        except Exception as e:
            return {"error": str(e)}



def main():
    api = InstallerAPI()
    window = webview.create_window(
        "Zotero MCP Setup",
        html=HTML,
        width=580,
        height=720,
        resizable=True,
        js_api=api,
        background_color="#FEFBF6"
    )
    api.set_window(window)
    webview.start(debug=False)


if __name__ == "__main__":
    main()
